using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
string? apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable and try again.");
    return 1;
}

string model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notepad = new Notepad();
var webSearch = new WebSearchTool();

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
];

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the SearchAsync tool to find relevant web pages.
        2. Use the FetchPageAsync tool to read promising results.
        3. Use the AddNote tool to record key findings as you go.
        4. After gathering enough information, use GetNotes to review
           everything you collected, then produce a well-structured
           summary with references.
        Be thorough — perform multiple searches with varied queries
        to cover different angles of the topic.
        """,
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent (.NET 10)       ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.\n");

var session = new ChatClientAgentSession();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    string? input = Console.ReadLine();
    if (input is null || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    if (string.IsNullOrWhiteSpace(input))
        continue;

    notepad.Clear();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching — this may take a moment...\n");
    Console.ResetColor();

    try
    {
        AgentResponse response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {input}",
            session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine(response.Text);
        Console.ResetColor();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

return 0;

// ═══════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Provides web search and page fetching capabilities.</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Search the web for a query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (default 5)")] int maxResults = 5)
    {
        // Use DuckDuckGo HTML search — no API key required.
        string encoded = WebUtility.UrlEncode(query);
        string url = $"https://html.duckduckgo.com/html/?q={encoded}";

        try
        {
            string html = await s_http.GetStringAsync(url);
            return ParseDuckDuckGoResults(html, maxResults);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch a web page and return its text content (HTML tags stripped).")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url,
        [Description("Maximum character length of returned content (default 4000)")] int maxLength = 4000)
    {
        try
        {
            string html = await s_http.GetStringAsync(url);
            string text = StripHtml(html);
            return text.Length > maxLength ? text[..maxLength] + "\n[...truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    // ------------------------------------------------------------------
    // Helpers
    // ------------------------------------------------------------------

    private static string ParseDuckDuckGoResults(string html, int max)
    {
        var sb = new StringBuilder();
        int count = 0;

        // Match result entries: <a class="result__a" href="...">title</a>
        // and snippet: <a class="result__snippet" ...>snippet</a>
        var linkPattern = new Regex(
            @"<a\s+[^>]*class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        var snippetPattern = new Regex(
            @"<a\s+[^>]*class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        foreach (Match link in links)
        {
            if (count >= max) break;

            string href = WebUtility.HtmlDecode(link.Groups[1].Value);
            // DuckDuckGo wraps URLs in a redirect — extract the actual URL.
            var uddg = Regex.Match(href, @"uddg=([^&]+)");
            string actualUrl = uddg.Success ? WebUtility.UrlDecode(uddg.Groups[1].Value) : href;

            string title = StripHtml(link.Groups[2].Value).Trim();
            string snippet = count < snippets.Count
                ? StripHtml(snippets[count].Groups[1].Value).Trim()
                : "";

            sb.AppendLine($"[{count + 1}] {title}");
            sb.AppendLine($"    URL: {actualUrl}");
            if (!string.IsNullOrEmpty(snippet))
                sb.AppendLine($"    {snippet}");
            sb.AppendLine();

            count++;
        }

        return count > 0
            ? sb.ToString()
            : "No results found.";
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then collapse whitespace.
        string noScript = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", " ",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        string noTags = Regex.Replace(noScript, @"<[^>]+>", " ");
        string decoded = WebUtility.HtmlDecode(noTags);
        return Regex.Replace(decoded, @"\s+", " ").Trim();
    }
}

/// <summary>In-memory notepad for the agent to store research findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important findings during research.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

